import React from 'react';
import mockData from '@/data/mockProfileData.json';

export default function MessagesTab() {
  const { messages } = mockData;

  return (
    <div className="space-y-6">
      <div className="border-b border-neutral-100 pb-2 mb-6 flex justify-between items-center">
        <h3 className="text-xl font-bold text-neutral-900">Messages</h3>
        <span className="text-sm font-medium text-primary-600 bg-primary-50 px-3 py-1 rounded-full">
          {messages.filter(m => m.unread).length} Unread
        </span>
      </div>

      <div className="bg-white rounded-2xl border border-neutral-100 shadow-sm overflow-hidden flex flex-col divide-y divide-neutral-100">
        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`p-5 flex gap-4 hover:bg-neutral-50 cursor-pointer transition-colors
              ${msg.unread ? 'bg-primary-50/30' : ''}
            `}
          >
            <div className="relative flex-shrink-0">
              <img 
                src={msg.senderImage} 
                alt={msg.senderName} 
                className="w-12 h-12 rounded-full object-cover border border-neutral-200"
              />
              {msg.unread && (
                <span className="absolute top-0 right-0 w-3 h-3 bg-primary-500 border-2 border-white rounded-full"></span>
              )}
            </div>

            <div className="flex-1 min-w-0">
              <div className="flex justify-between items-baseline mb-1">
                <h4 className={`text-base truncate ${msg.unread ? 'font-bold text-neutral-900' : 'font-medium text-neutral-800'}`}>
                  {msg.senderName}
                </h4>
                <span className="text-xs text-neutral-500 whitespace-nowrap ml-2">
                  {msg.timestamp}
                </span>
              </div>
              <p className={`text-sm truncate ${msg.unread ? 'text-neutral-800 font-medium' : 'text-neutral-500'}`}>
                {msg.preview}
              </p>
            </div>
          </div>
        ))}
      </div>

      {messages.length === 0 && (
        <div className="text-center py-16">
          <p className="text-neutral-500">No messages yet.</p>
        </div>
      )}
    </div>
  );
}

import React from 'react';
import { BookOpen, Bookmark, MessageSquare, Map } from 'lucide-react';
import mockData from '@/data/mockProfileData.json';

export default function ProfileOverview() {
  const { user } = mockData;

  const statCards = [
    { label: 'Stories Uploaded', value: user.stats.storiesUploaded, icon: BookOpen, color: 'text-blue-600', bg: 'bg-blue-50' },
    { label: 'Saved Destinations', value: user.stats.savedDestinations, icon: Bookmark, color: 'text-emerald-600', bg: 'bg-emerald-50' },
    { label: 'Messages', value: user.stats.messages, icon: MessageSquare, color: 'text-purple-600', bg: 'bg-purple-50' },
    { label: 'Places Explored', value: user.stats.placesExplored, icon: Map, color: 'text-orange-600', bg: 'bg-orange-50' },
  ];

  return (
    <div className="space-y-6">
      <div className="bg-white rounded-2xl p-6 shadow-sm border border-neutral-100 mb-6">
        <h3 className="text-xl font-bold text-neutral-900 mb-2">Welcome back, {user.fullName.split(' ')[0]}!</h3>
        <p className="text-neutral-600">Here's a quick overview of your journey on Echoes of Nepal.</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        {statCards.map((stat, i) => {
          const Icon = stat.icon;
          return (
            <div key={i} className="bg-white rounded-2xl p-6 shadow-sm border border-neutral-100 flex items-center gap-4 hover:shadow-md transition-shadow">
              <div className={`p-4 rounded-xl ${stat.bg}`}>
                <Icon size={24} className={stat.color} />
              </div>
              <div>
                <p className="text-2xl font-bold text-neutral-900">{stat.value}</p>
                <p className="text-sm text-neutral-500 font-medium">{stat.label}</p>
              </div>
            </div>
          );
        })}
      </div>

      {/* Placeholder for a featured graphic or quick actions could go here */}
      <div className="bg-gradient-to-br from-primary-600 to-primary-800 rounded-2xl p-8 text-white mt-8 shadow-md relative overflow-hidden">
        {/* Abstract shapes for decoration */}
        <div className="absolute top-0 right-0 -mr-8 -mt-8 w-32 h-32 rounded-full bg-white opacity-10 blur-2xl"></div>
        <div className="absolute bottom-0 left-0 -ml-8 -mb-8 w-24 h-24 rounded-full bg-white opacity-10 blur-xl"></div>

        <div className="relative z-10 flex flex-col md:flex-row items-center justify-between gap-6">
          <div className="text-center md:text-left">
            <h3 className="text-2xl font-bold mb-2">Ready for your next adventure?</h3>
            <p className="text-primary-100 opacity-90 max-w-md">Discover new hidden gems across Nepal or share a story from your recent travels.</p>
          </div>
          <div className="flex gap-3 w-full md:w-auto">
            <button className="flex-1 md:flex-none px-6 py-3 bg-white text-primary-700 rounded-xl font-bold hover:bg-neutral-50 transition-colors shadow-sm">
              Explore Map
            </button>
            <button className="flex-1 md:flex-none px-6 py-3 bg-primary-700 text-white rounded-xl font-bold border border-primary-500 hover:bg-primary-800 transition-colors shadow-sm">
              Tell a Story
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

import React from 'react';
import { 
  User, 
  BookOpen, 
  MessageSquare, 
  Bookmark, 
  Activity, 
  Settings,
  MapPin,
  Calendar
} from 'lucide-react';
import mockData from '@/data/mockProfileData.json';

interface ProfileSidebarProps {
  activeTab: string;
  setActiveTab: (tab: string) => void;
}

export default function ProfileSidebar({ activeTab, setActiveTab }: ProfileSidebarProps) {
  const { user } = mockData;

  const tabs = [
    { id: 'overview', label: 'Overview', icon: User },
    { id: 'stories', label: 'My Stories', icon: BookOpen },
    { id: 'messages', label: 'Messages', icon: MessageSquare },
    { id: 'saved', label: 'Saved', icon: Bookmark },
    { id: 'activity', label: 'Recent Activity', icon: Activity },
    { id: 'settings', label: 'Settings', icon: Settings },
  ];

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-neutral-100 overflow-hidden flex flex-col h-full">
      {/* Profile Header Card */}
      <div className="p-6 border-b border-neutral-100 flex flex-col items-center text-center">
        <div className="relative w-24 h-24 mb-4">
          <img 
            src={user.profileImage} 
            alt={user.fullName} 
            className="w-full h-full object-cover rounded-full border-4 border-white shadow-md"
          />
        </div>
        <h2 className="text-xl font-bold text-neutral-900">{user.fullName}</h2>
        <p className="text-neutral-500 text-sm mb-4">{user.username}</p>

        <p className="text-sm text-neutral-600 mb-4 line-clamp-2">
          {user.bio}
        </p>

        <div className="flex flex-col gap-2 text-sm text-neutral-500 w-full mt-2">
          <div className="flex items-center gap-2 justify-center">
            <MapPin size={16} />
            <span>{user.location}</span>
          </div>
          <div className="flex items-center gap-2 justify-center">
            <Calendar size={16} />
            <span>Joined {user.joinDate}</span>
          </div>
        </div>
      </div>

      {/* Navigation Tabs */}
      <nav className="flex-1 p-4 flex flex-col gap-1 overflow-y-auto w-full">
        {tabs.map((tab) => {
          const Icon = tab.icon;
          const isActive = activeTab === tab.id;

          return (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-200 text-left w-full
                ${isActive 
                  ? 'bg-primary-50 text-primary-700 font-medium' 
                  : 'text-neutral-600 hover:bg-neutral-50 hover:text-neutral-900'
                }
              `}
            >
              <Icon size={20} className={isActive ? 'text-primary-600' : 'text-neutral-400'} />
              <span>{tab.label}</span>
            </button>
          );
        })}
      </nav>
    </div>
  );
}

import React from 'react';
import { Eye, Clock, Upload, Bookmark, Map } from 'lucide-react';
import mockData from '@/data/mockProfileData.json';

export default function RecentActivityTab() {
  const { recentActivity } = mockData;

  const getIconForType = (type: string) => {
    switch (type) {
      case 'viewed': return <Eye size={18} className="text-blue-500" />;
      case 'uploaded': return <Upload size={18} className="text-emerald-500" />;
      case 'saved': return <Bookmark size={18} className="text-purple-500" />;
      case 'explored': return <Map size={18} className="text-orange-500" />;
      default: return <Clock size={18} className="text-neutral-500" />;
    }
  };

  const getBgForType = (type: string) => {
    switch (type) {
      case 'viewed': return 'bg-blue-50 border-blue-100';
      case 'uploaded': return 'bg-emerald-50 border-emerald-100';
      case 'saved': return 'bg-purple-50 border-purple-100';
      case 'explored': return 'bg-orange-50 border-orange-100';
      default: return 'bg-neutral-50 border-neutral-100';
    }
  };

  return (
    <div className="space-y-6">
      <div className="border-b border-neutral-100 pb-4 mb-6">
        <h3 className="text-xl font-bold text-neutral-900">Recent Activity</h3>
      </div>

      <div className="relative border-l-2 border-neutral-100 ml-4 space-y-8 pb-4">
        {recentActivity.map((activity, index) => (
          <div key={activity.id} className="relative pl-8 group">
            {/* Timeline dot/icon */}
            <div className={`absolute -left-[17px] top-0.5 w-8 h-8 rounded-full border flex items-center justify-center shadow-sm z-10 transition-transform group-hover:scale-110
              ${getBgForType(activity.type)}
            `}>
              {getIconForType(activity.type)}
            </div>

            <div className="bg-white p-4 rounded-xl border border-neutral-100 shadow-sm hover:shadow-md transition-shadow">
              <p className="text-neutral-800 font-medium mb-1">{activity.description}</p>
              <div className="flex items-center text-xs text-neutral-500 gap-1.5">
                <Clock size={12} />
                {activity.timestamp}
              </div>
            </div>
          </div>
        ))}

        {/* End of timeline marker */}
        <div className="relative pl-8 pt-4">
          <div className="absolute -left-[9px] top-6 w-4 h-4 rounded-full bg-neutral-200 border-4 border-white"></div>
        </div>
      </div>

      {recentActivity.length === 0 && (
        <div className="text-center py-12 bg-neutral-50 border border-neutral-100 border-dashed rounded-2xl">
          <p className="text-neutral-500">No recent activity found.</p>
        </div>
      )}
    </div>
  );
}

import React from 'react';
import { BookmarkMinus, MapPin, BookOpen } from 'lucide-react';
import mockData from '@/data/mockProfileData.json';

export default function SavedTab() {
  const { saved } = mockData;

  const categories = ['All', 'Destination', 'Story'];
  const [activeFilter, setActiveFilter] = React.useState('All');

  const filteredItems = saved.filter(item => 
    activeFilter === 'All' ? true : item.category === activeFilter
  );

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-6 border-b border-neutral-100 pb-4">
        <h3 className="text-xl font-bold text-neutral-900">Saved Items</h3>

        {/* Filter Pills */}
        <div className="flex gap-2">
          {categories.map(cat => (
            <button
              key={cat}
              onClick={() => setActiveFilter(cat)}
              className={`px-4 py-1.5 rounded-full text-sm font-medium transition-colors border
                ${activeFilter === cat 
                  ? 'bg-neutral-900 text-white border-neutral-900' 
                  : 'bg-white text-neutral-600 border-neutral-200 hover:bg-neutral-50'
                }
              `}
            >
              {cat}
            </button>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredItems.map((item) => (
          <div key={item.id} className="bg-white rounded-2xl border border-neutral-100 overflow-hidden hover:shadow-md transition-all group flex flex-col">
            <div className="relative h-40 overflow-hidden">
              <img 
                src={item.image} 
                alt={item.title} 
                className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300"
              />
              <div className="absolute top-3 left-3 flex gap-2">
                <span className={`text-xs font-bold px-2.5 py-1 rounded-md flex items-center gap-1.5 shadow-sm
                  ${item.category === 'Destination' ? 'bg-emerald-100 text-emerald-800' : 'bg-blue-100 text-blue-800'}
                `}>
                  {item.category === 'Destination' ? <MapPin size={12} /> : <BookOpen size={12} />}
                  {item.category}
                </span>
              </div>
              <button 
                className="absolute top-3 right-3 p-2 bg-white/90 backdrop-blur rounded-full text-neutral-400 hover:text-red-500 hover:bg-red-50 transition-colors opacity-0 group-hover:opacity-100 shadow-sm"
                title="Remove from saved"
              >
                <BookmarkMinus size={18} />
              </button>
            </div>

            <div className="p-4 flex flex-col flex-1">
              <h4 className="font-bold text-neutral-900 line-clamp-2 mb-1 group-hover:text-primary-600 transition-colors">
                {item.title}
              </h4>
              <p className="text-sm text-neutral-500 mt-auto flex items-center gap-1">
                <MapPin size={14} />
                {item.district}
              </p>
            </div>
          </div>
        ))}
      </div>

      {filteredItems.length === 0 && (
        <div className="text-center py-16 bg-neutral-50 border border-neutral-100 border-dashed rounded-2xl">
          <p className="text-neutral-500">No saved items found in this category.</p>
        </div>
      )}
    </div>
  );
}

import React from 'react';
import { User, Lock, Bell, Palette } from 'lucide-react';
import mockData from '@/data/mockProfileData.json';

export default function SettingsTab() {
  const { user } = mockData;
  const [activeSection, setActiveSection] = React.useState('profile');

  const sections = [
    { id: 'profile', label: 'Edit Profile', icon: User },
    { id: 'security', label: 'Security & Password', icon: Lock },
    { id: 'notifications', label: 'Notifications', icon: Bell },
    { id: 'appearance', label: 'Appearance', icon: Palette },
  ];

  return (
    <div className="space-y-6">
      <div className="border-b border-neutral-100 pb-4 mb-6">
        <h3 className="text-xl font-bold text-neutral-900">Account Settings</h3>
      </div>

      <div className="flex flex-col md:flex-row gap-8">
        {/* Settings Navigation */}
        <div className="w-full md:w-64 flex-shrink-0">
          <nav className="flex flex-col gap-1">
            {sections.map((section) => {
              const Icon = section.icon;
              const isActive = activeSection === section.id;

              return (
                <button
                  key={section.id}
                  onClick={() => setActiveSection(section.id)}
                  className={`flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-200 text-left text-sm font-medium
                    ${isActive 
                      ? 'bg-neutral-900 text-white shadow-sm' 
                      : 'text-neutral-600 hover:bg-neutral-50 hover:text-neutral-900'
                    }
                  `}
                >
                  <Icon size={18} className={isActive ? 'text-neutral-300' : 'text-neutral-400'} />
                  {section.label}
                </button>
              );
            })}
          </nav>
        </div>

        {/* Settings Content Area */}
        <div className="flex-1">
          {activeSection === 'profile' && (
            <div className="bg-white rounded-2xl border border-neutral-100 shadow-sm p-6 space-y-6">
              <h4 className="text-lg font-bold text-neutral-900 mb-4">Profile Information</h4>

              <div className="flex items-center gap-6 mb-8">
                <img 
                  src={user.profileImage} 
                  alt={user.fullName} 
                  className="w-20 h-20 rounded-full object-cover border border-neutral-200"
                />
                <div>
                  <div className="flex gap-3">
                    <button className="px-4 py-2 bg-neutral-900 text-white rounded-lg text-sm font-medium hover:bg-neutral-800 transition-colors">
                      Change Avatar
                    </button>
                    <button className="px-4 py-2 bg-neutral-100 text-neutral-700 rounded-lg text-sm font-medium hover:bg-neutral-200 transition-colors">
                      Remove
                    </button>
                  </div>
                  <p className="text-xs text-neutral-500 mt-2">JPG, GIF or PNG. 1MB max.</p>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-sm font-medium text-neutral-700">Full Name</label>
                  <input 
                    type="text" 
                    defaultValue={user.fullName}
                    className="w-full px-4 py-2 border border-neutral-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500 outline-none transition-shadow"
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-medium text-neutral-700">Username</label>
                  <input 
                    type="text" 
                    defaultValue={user.username.replace('@', '')}
                    className="w-full px-4 py-2 border border-neutral-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500 outline-none transition-shadow"
                  />
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-sm font-medium text-neutral-700">Bio</label>
                <textarea 
                  rows={4}
                  defaultValue={user.bio}
                  className="w-full px-4 py-2 border border-neutral-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500 outline-none transition-shadow resize-none"
                />
              </div>

              <div className="space-y-2">
                <label className="text-sm font-medium text-neutral-700">Location</label>
                <input 
                  type="text" 
                  defaultValue={user.location}
                  className="w-full px-4 py-2 border border-neutral-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500 outline-none transition-shadow"
                />
              </div>

              <div className="pt-4 flex justify-end gap-3 border-t border-neutral-100">
                <button className="px-6 py-2 bg-neutral-100 text-neutral-700 rounded-xl font-medium hover:bg-neutral-200 transition-colors">
                  Cancel
                </button>
                <button className="px-6 py-2 bg-primary-600 text-white rounded-xl font-bold hover:bg-primary-700 transition-colors shadow-sm focus:ring-4 focus:ring-primary-100">
                  Save Changes
                </button>
              </div>
            </div>
          )}

          {activeSection !== 'profile' && (
            <div className="bg-white rounded-2xl border border-neutral-100 shadow-sm p-6 flex flex-col items-center justify-center min-h-[300px] text-center">
              <Lock size={48} className="text-neutral-200 mb-4" />
              <h4 className="text-lg font-bold text-neutral-900 mb-2">Section under construction</h4>
              <p className="text-neutral-500 max-w-sm">
                This settings panel is a placeholder for the "{sections.find(s => s.id === activeSection)?.label}" configuration.
              </p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
